// SellDustCalculator defines how to compute dust for a sell bet.
type SellDustCalculator interface {
	DustForSell(sellBet models.Bet, allBets []models.Bet) int64
}

// ConstantSellDustCalculator returns a fixed dust amount for every sell.
type ConstantSellDustCalculator struct {
	DustPerSell int64
}

func (c ConstantSellDustCalculator) DustForSell(sellBet models.Bet, allBets []models.Bet) int64 {
	if sellBet.Amount < 0 {
		return c.DustPerSell
	}
	return 0
}

var defaultSellDustCalculator = ConstantSellDustCalculator{DustPerSell: 1}

type marketDustCalculator struct {
	volumeCalculator VolumeCalculator
	sellCalculator   SellDustCalculator
}

var defaultMarketDustCalculator = marketDustCalculator{
	volumeCalculator: defaultVolumeCalculator,
	sellCalculator:   defaultSellDustCalculator,
}

// GetMarketVolumeWithDust returns the market volume including accumulated dust from selling
// This ensures currency conservation by accounting for dust that remains in the market
func GetMarketVolumeWithDust(bets []models.Bet) int64 {
	return defaultMarketDustCalculator.VolumeWithDust(bets)
}

// calculateDustStack computes total dust accumulated from all sell transactions
// Uses O(n) single-pass algorithm with chronological processing
func calculateDustStack(bets []models.Bet) int64 {
	return defaultMarketDustCalculator.Dust(bets)
}

// GetMarketDustWithCalculator allows callers to supply a custom dust calculator.
// Falls back to default dust behavior if a nil calculator is provided.
func GetMarketDustWithCalculator(bets []models.Bet, calculator SellDustCalculator) int64 {
	if calculator == nil {
		calculator = defaultSellDustCalculator
	}
	return marketDustCalculator{
		volumeCalculator: defaultVolumeCalculator,
		sellCalculator:   calculator,
	}.Dust(bets)
}

func calculateDustStackWithCalculator(bets []models.Bet, calculator SellDustCalculator) int64 {
	if calculator == nil {
		return 0
	}

	var totalDust int64
	for _, bet := range bets {
		if bet.Amount >= 0 {
			continue
		}
		totalDust += calculator.DustForSell(bet, bets)
	}
	return totalDust
}

// calculateDustForSell determines dust generated by a specific sell transaction
// This is a placeholder implementation - actual dust calculation will depend on
// the selling mechanism and how shares are valued at the time of sale
func calculateDustForSell(sellBet models.Bet, allBets []models.Bet) int64 {
	return defaultMarketDustCalculator.DustForSell(sellBet, allBets)
}

// GetMarketDust calculates accumulated dust for a market
// This is a utility function for dust-related calculations
func GetMarketDust(bets []models.Bet) int64 {
	return defaultMarketDustCalculator.Dust(bets)
}

func sortBetsChronologically(bets []models.Bet) []models.Bet {
	sortedBets := make([]models.Bet, len(bets))
	copy(sortedBets, bets)
	sort.Slice(sortedBets, func(i, j int) bool {
		return sortedBets[i].PlacedAt.Before(sortedBets[j].PlacedAt)
	})
	return sortedBets
}

func (c marketDustCalculator) VolumeWithDust(bets []models.Bet) int64 {
	return c.volumeCalculator.Volume(bets) + c.Dust(bets)
}

func (c marketDustCalculator) Dust(bets []models.Bet) int64 {
	if len(bets) == 0 {
		return 0
	}
	return calculateDustStackWithCalculator(sortBetsChronologically(bets), c.sellCalculator)
}

func (c marketDustCalculator) DustForSell(sellBet models.Bet, allBets []models.Bet) int64 {
	if c.sellCalculator == nil {
		return 0
	}
	return c.sellCalculator.DustForSell(sellBet, allBets)
}

package positionsmath

import (
	"sort"
	"time"
)

// UserHolder carries the ordering data used for deterministic valuation adjustments.
type UserHolder struct {
	Username     string
	RoundedValue int64
	EarliestBet  time.Time
}

type UserValuationAdjuster interface {
	Adjust(
		userValuations map[string]UserValuationResult,
		earliestBets map[string]time.Time,
		targetMarketVolume int64,
	) map[string]UserValuationResult
}

type ByValBetTimeUsername []UserHolder

func (s ByValBetTimeUsername) Len() int      { return len(s) }
func (s ByValBetTimeUsername) Swap(i, j int) { s[i], s[j] = s[j], s[i] }
func (s ByValBetTimeUsername) Less(i, j int) bool {
	if s[i].RoundedValue != s[j].RoundedValue {
		return s[i].RoundedValue > s[j].RoundedValue
	}
	if !s[i].EarliestBet.Equal(s[j].EarliestBet) {
		return s[i].EarliestBet.Before(s[j].EarliestBet)
	}
	return s[i].Username < s[j].Username
}

type deterministicValuationAdjuster struct{}

var defaultUserValuationAdjuster UserValuationAdjuster = deterministicValuationAdjuster{}

// AdjustUserValuationsToMarketVolume ensures user values match total market volume,
// distributing rounding delta deterministically. Only users with >0 value are adjusted.
func AdjustUserValuationsToMarketVolume(
	userValuations map[string]UserValuationResult,
	earliestBets map[string]time.Time,
	targetMarketVolume int64,
) map[string]UserValuationResult {
	return defaultUserValuationAdjuster.Adjust(userValuations, earliestBets, targetMarketVolume)
}

func (deterministicValuationAdjuster) Adjust(
	userValuations map[string]UserValuationResult,
	earliestBets map[string]time.Time,
	targetMarketVolume int64,
) map[string]UserValuationResult {
	filtered := filterWinningValuations(userValuations)
	if len(filtered) == 0 {
		return userValuations
	}

	holders, sum := buildUserHolders(filtered, earliestBets)
	return adjustValuations(filtered, holders, sum, targetMarketVolume)
}

// filterWinningValuations returns only users eligible for rounding adjustments.
func filterWinningValuations(all map[string]UserValuationResult) map[string]UserValuationResult {
	filtered := make(map[string]UserValuationResult, len(all))
	for username, val := range all {
		if val.RoundedValue > 0 {
			filtered[username] = val
		}
	}
	return filtered
}

// buildUserHolders builds the deterministic adjustment order and total adjusted value.
func buildUserHolders(
	userVals map[string]UserValuationResult,
	earliest map[string]time.Time,
) ([]UserHolder, int64) {
	var (
		holders []UserHolder
		sum     int64
	)
	for username, val := range userVals {
		sum += val.RoundedValue
		holders = append(holders, newUserHolder(username, val.RoundedValue, earliest[username]))
	}
	sort.Sort(ByValBetTimeUsername(holders))
	return holders, sum
}

func newUserHolder(username string, roundedValue int64, earliestBet time.Time) UserHolder {
	return UserHolder{
		Username:     username,
		RoundedValue: roundedValue,
		EarliestBet:  earliestBet,
	}
}

// adjustValuations spreads the rounding delta across the sorted holders.
func adjustValuations(
	userVals map[string]UserValuationResult,
	holders []UserHolder,
	sum int64,
	target int64,
) map[string]UserValuationResult {
	delta, adjustment := valuationDelta(sum, target)
	if delta == 0 {
		return userVals
	}

	holderCount := int64(len(holders))
	for i := int64(0); i < delta; i++ {
		holder := holders[i%holderCount]
		val := userVals[holder.Username]
		val.RoundedValue += adjustment
		userVals[holder.Username] = val
	}
	return userVals
}

func valuationDelta(currentSum, target int64) (int64, int64) {
	delta := target - currentSum
	if delta < 0 {
		return -delta, -1
	}
	return delta, 1
}

package positionsmath

import (
	"socialpredict/models"
	"sort"
	"time"
)

const (
	positionTypeYes     = "YES"
	positionTypeNo      = "NO"
	positionTypeNeutral = "NEUTRAL"
	positionTypeNone    = "NONE"
)

type positionTypeRule struct {
	position string
	matches  func(yesShares, noShares int64) bool
}

type MarketPositionSource interface {
	CalculateMarketPositions(snapshot MarketSnapshot, bets []models.Bet) ([]MarketPosition, error)
}

type UserSpendCalculator interface {
	Spend(bets []models.Bet, username string) int64
}

type EarliestBetTimeFinder interface {
	EarliestBetTime(bets []models.Bet, username string) time.Time
}

type PositionTypeResolver interface {
	Resolve(yesShares, noShares int64) string
}

var defaultPositionTypeRules = []positionTypeRule{
	{
		position: positionTypeYes,
		matches: func(yesShares, noShares int64) bool {
			return yesShares > 0 && noShares == 0
		},
	},
	{
		position: positionTypeNo,
		matches: func(yesShares, noShares int64) bool {
			return noShares > 0 && yesShares == 0
		},
	},
	{
		position: positionTypeNeutral,
		matches: func(yesShares, noShares int64) bool {
			return yesShares > 0 && noShares > 0
		},
	},
}

// UserProfitability represents a user's profitability data for a specific market.
type UserProfitability struct {
	Username       string    `json:"username"`
	CurrentValue   int64     `json:"currentValue"`
	TotalSpent     int64     `json:"totalSpent"`
	Profit         int64     `json:"profit"`
	Position       string    `json:"position"` // "YES", "NO", "NEUTRAL"
	YesSharesOwned int64     `json:"yesSharesOwned"`
	NoSharesOwned  int64     `json:"noSharesOwned"`
	EarliestBet    time.Time `json:"earliestBet"`
	Rank           int       `json:"rank"`
}

type LeaderboardCalculator struct {
	positions     MarketPositionSource
	spend         UserSpendCalculator
	earliest      EarliestBetTimeFinder
	positionTypes PositionTypeResolver
}

type defaultSpendCalculator struct{}
type defaultEarliestBetTimeFinder struct{}
type defaultPositionTypeResolver struct{}

var defaultLeaderboardCalculator = LeaderboardCalculator{
	positions:     NewPositionCalculator(),
	spend:         defaultSpendCalculator{},
	earliest:      defaultEarliestBetTimeFinder{},
	positionTypes: defaultPositionTypeResolver{},
}

// CalculateMarketLeaderboard ranks users in a market by profitability.
func CalculateMarketLeaderboard(snapshot MarketSnapshot, bets []models.Bet) ([]UserProfitability, error) {
	return defaultLeaderboardCalculator.Calculate(snapshot, bets)
}

func (c LeaderboardCalculator) Calculate(snapshot MarketSnapshot, bets []models.Bet) ([]UserProfitability, error) {
	if len(bets) == 0 {
		return []UserProfitability{}, nil
	}
	c = c.withDefaults()

	positions, err := c.positions.CalculateMarketPositions(snapshot, bets)
	if err != nil {
		return nil, err
	}

	leaderboard := buildLeaderboard(positions, bets, c.spend, c.earliest, c.positionTypes)
	sortLeaderboard(leaderboard)
	assignLeaderboardRanks(leaderboard)
	return leaderboard, nil
}

func (c LeaderboardCalculator) withDefaults() LeaderboardCalculator {
	if c.positions == nil {
		c.positions = NewPositionCalculator()
	}
	if c.spend == nil {
		c.spend = defaultSpendCalculator{}
	}
	if c.earliest == nil {
		c.earliest = defaultEarliestBetTimeFinder{}
	}
	if c.positionTypes == nil {
		c.positionTypes = defaultPositionTypeResolver{}
	}
	return c
}

func buildLeaderboard(
	positions []MarketPosition,
	bets []models.Bet,
	spend UserSpendCalculator,
	earliest EarliestBetTimeFinder,
	positionTypes PositionTypeResolver,
) []UserProfitability {
	leaderboard := make([]UserProfitability, 0, len(positions))
	for _, position := range positions {
		if hasNoOpenPosition(position) {
			continue
		}
		leaderboard = append(leaderboard, newUserProfitability(position, bets, spend, earliest, positionTypes))
	}
	return leaderboard
}

func hasNoOpenPosition(position MarketPosition) bool {
	return position.YesSharesOwned == 0 && position.NoSharesOwned == 0
}

func newUserProfitability(
	position MarketPosition,
	bets []models.Bet,
	spend UserSpendCalculator,
	earliest EarliestBetTimeFinder,
	positionTypes PositionTypeResolver,
) UserProfitability {
	totalSpent := spend.Spend(bets, position.Username)
	return UserProfitability{
		Username:       position.Username,
		CurrentValue:   position.Value,
		TotalSpent:     totalSpent,
		Profit:         position.Value - totalSpent,
		Position:       positionTypes.Resolve(position.YesSharesOwned, position.NoSharesOwned),
		YesSharesOwned: position.YesSharesOwned,
		NoSharesOwned:  position.NoSharesOwned,
		EarliestBet:    earliest.EarliestBetTime(bets, position.Username),
	}
}

func sortLeaderboard(leaderboard []UserProfitability) {
	sort.Slice(leaderboard, func(i, j int) bool {
		if leaderboard[i].Profit == leaderboard[j].Profit {
			return leaderboard[i].EarliestBet.Before(leaderboard[j].EarliestBet)
		}
		return leaderboard[i].Profit > leaderboard[j].Profit
	})
}

func assignLeaderboardRanks(leaderboard []UserProfitability) {
	for i := range leaderboard {
		leaderboard[i].Rank = i + 1
	}
}

// CalculateUserSpend sums a user's total spend (positive buys, negative sells).
func CalculateUserSpend(bets []models.Bet, username string) int64 {
	return defaultSpendCalculator{}.Spend(bets, username)
}

func (defaultSpendCalculator) Spend(bets []models.Bet, username string) int64 {
	var total int64
	forEachUserBet(bets, username, func(bet models.Bet) {
		total += bet.Amount
	})
	return total
}

// GetEarliestBetTime returns the earliest bet timestamp for the user.
func GetEarliestBetTime(bets []models.Bet, username string) time.Time {
	return defaultEarliestBetTimeFinder{}.EarliestBetTime(bets, username)
}

func (defaultEarliestBetTimeFinder) EarliestBetTime(bets []models.Bet, username string) time.Time {
	var earliest time.Time
	first := true

	forEachUserBet(bets, username, func(bet models.Bet) {
		if first || bet.PlacedAt.Before(earliest) {
			earliest = bet.PlacedAt
			first = false
		}
	})

	return earliest
}

// DeterminePositionType identifies whether the user holds YES, NO, or both.
func DeterminePositionType(yesShares, noShares int64) string {
	return defaultPositionTypeResolver{}.Resolve(yesShares, noShares)
}

func (defaultPositionTypeResolver) Resolve(yesShares, noShares int64) string {
	for _, rule := range defaultPositionTypeRules {
		if rule.matches(yesShares, noShares) {
			return rule.position
		}
	}
	return positionTypeNone
}

func forEachUserBet(bets []models.Bet, username string, visit func(models.Bet)) {
	for _, bet := range bets {
		if bet.Username != username {
			continue
		}
		visit(bet)
	}
}

package positionsmath

import (
	"math"
	"time"
)

type valuationRule struct {
	matches func(UserMarketPosition) bool
	value   func(UserMarketPosition, float64) float64
}

type resolutionRule struct {
	finalProbability float64
	resolvedValue    func(UserMarketPosition) float64
}

type ValuationModel interface {
	FinalProbability(currentProbability float64, isResolved bool, resolutionResult string) float64
	PositionValue(position UserMarketPosition, finalProbability float64, isResolved bool, resolutionResult string) float64
}

var unresolvedValuationRules = []valuationRule{
	{
		matches: func(position UserMarketPosition) bool { return position.YesSharesOwned > 0 },
		value: func(position UserMarketPosition, probability float64) float64 {
			return float64(position.YesSharesOwned) * probability
		},
	},
	{
		matches: func(position UserMarketPosition) bool { return position.NoSharesOwned > 0 },
		value: func(position UserMarketPosition, probability float64) float64 {
			return float64(position.NoSharesOwned) * (1 - probability)
		},
	},
}

var resolvedValuationRules = map[string]resolutionRule{
	positionTypeYes: {
		finalProbability: 1.0,
		resolvedValue: func(position UserMarketPosition) float64 {
			return float64(position.YesSharesOwned)
		},
	},
	positionTypeNo: {
		finalProbability: 0.0,
		resolvedValue: func(position UserMarketPosition) float64 {
			return float64(position.NoSharesOwned)
		},
	},
}

type UserValuationResult struct {
	Username     string
	RoundedValue int64
}

type valuationModel struct{}

type ValuationCalculator struct {
	model    ValuationModel
	adjuster UserValuationAdjuster
}

var defaultValuationCalculator = ValuationCalculator{
	model:    valuationModel{},
	adjuster: defaultUserValuationAdjuster,
}

func CalculateRoundedUserValuationsFromUserMarketPositions(
	userPositions map[string]UserMarketPosition,
	currentProbability float64,
	totalVolume int64,
	isResolved bool,
	resolutionResult string,
	earliestBets map[string]time.Time,
) (map[string]UserValuationResult, error) {
	return defaultValuationCalculator.Calculate(
		userPositions,
		currentProbability,
		totalVolume,
		isResolved,
		resolutionResult,
		earliestBets,
	)
}

func (c ValuationCalculator) Calculate(
	userPositions map[string]UserMarketPosition,
	currentProbability float64,
	totalVolume int64,
	isResolved bool,
	resolutionResult string,
	earliestBets map[string]time.Time,
) (map[string]UserValuationResult, error) {
	c = c.withDefaults()
	result := make(map[string]UserValuationResult)
	finalProb := c.model.FinalProbability(currentProbability, isResolved, resolutionResult)

	for username, pos := range userPositions {
		roundedVal := int64(math.Round(c.model.PositionValue(pos, finalProb, isResolved, resolutionResult)))

		result[username] = UserValuationResult{
			Username:     username,
			RoundedValue: roundedVal,
		}
	}

	adjusted := c.adjuster.Adjust(result, earliestBets, totalVolume)
	return adjusted, nil
}

func (c ValuationCalculator) withDefaults() ValuationCalculator {
	if c.model == nil {
		c.model = valuationModel{}
	}
	if c.adjuster == nil {
		c.adjuster = defaultUserValuationAdjuster
	}
	return c
}

func getFinalProbabilityFromMarketModel(
	currentProbability float64,
	isResolved bool,
	resolutionResult string,
) float64 {
	return valuationModel{}.FinalProbability(currentProbability, isResolved, resolutionResult)
}

func (valuationModel) FinalProbability(currentProbability float64, isResolved bool, resolutionResult string) float64 {
	if !isResolved {
		return currentProbability
	}
	rule, ok := resolvedValuationRules[resolutionResult]
	if !ok {
		return currentProbability
	}
	return rule.finalProbability
}

func calculatePositionValue(
	position UserMarketPosition,
	finalProbability float64,
	isResolved bool,
	resolutionResult string,
) float64 {
	return valuationModel{}.PositionValue(position, finalProbability, isResolved, resolutionResult)
}

func (valuationModel) PositionValue(
	position UserMarketPosition,
	finalProbability float64,
	isResolved bool,
	resolutionResult string,
) float64 {
	if isResolved {
		if rule, ok := resolvedValuationRules[resolutionResult]; ok {
			return rule.resolvedValue(position)
		}
		return 0
	}

	for _, rule := range unresolvedValuationRules {
		if rule.matches(position) {
			return rule.value(position, finalProbability)
		}
	}
	return 0
}

package positionsmath

import (
	"time"

	"socialpredict/internal/domain/math/outcomes/dbpm"
	"socialpredict/internal/domain/math/probabilities/wpam"
	"socialpredict/models"
)

type defaultProbabilityProvider struct {
	calculator wpam.ProbabilityCalculator
}

type defaultNetPositionCalculator struct{}

// NewWPAMProbabilityProvider constructs a WPAM-backed probability provider with the supplied calculator.
func NewWPAMProbabilityProvider(calculator wpam.ProbabilityCalculator) ProbabilityProvider {
	return defaultProbabilityProvider{calculator: calculator}
}

func (p defaultProbabilityProvider) Calculate(createdAt time.Time, bets []models.Bet) []wpam.ProbabilityChange {
	calc := p.calculator
	if calc.Seeds().InitialSubsidization == 0 {
		calc = wpam.NewProbabilityCalculator(nil)
	}
	return calc.CalculateMarketProbabilitiesWPAM(createdAt, bets)
}

func (p defaultProbabilityProvider) Current(changes []wpam.ProbabilityChange) float64 {
	return wpam.GetCurrentProbability(changes)
}

func (defaultNetPositionCalculator) CalculateNetPositions(sortedBets []models.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	yesShares, noShares := dbpm.DivideUpMarketPoolSharesDBPM(sortedBets, probabilityChanges)
	coursePayouts := dbpm.CalculateCoursePayoutsDBPM(sortedBets, probabilityChanges)
	yesFactor, noFactor := dbpm.CalculateNormalizationFactorsDBPM(yesShares, noShares, coursePayouts)
	scaledPayouts := dbpm.CalculateScaledPayoutsDBPM(sortedBets, coursePayouts, yesFactor, noFactor)
	finalPayouts := dbpm.AdjustPayouts(sortedBets, scaledPayouts)
	aggregatedPositions := dbpm.AggregateUserPayoutsDBPM(sortedBets, finalPayouts)
	return dbpm.NetAggregateMarketPositions(aggregatedPositions)
}

